package ru.memearena.ratelimit; import org.springframework.http.HttpStatus; import ru.memearena.error.*; public class RateLimitExceededException extends ApiException { private final long retryAfterSeconds; public RateLimitExceededException(long retryAfterSeconds){super(HttpStatus.TOO_MANY_REQUESTS,ErrorCode.RATE_LIMIT_EXCEEDED,"Rate limit exceeded"); this.retryAfterSeconds=Math.max(1,retryAfterSeconds);} public long retryAfterSeconds(){return retryAfterSeconds;} }
